+fn make_artifact(path: &str, kind: ArtifactKind, size: u64) -> ArtifactEntry {
+    ArtifactEntry {
+        path: path.to_string(),
+        kind,
+        content_hash: format!("hash_{path}"),
+        size_bytes: size,
+        redacted: false,
+    }
